#include <bits/stdc++.h>
using namespace std;
vector<int> a[1001];
int bfs(int n){
    queue<int> b;
    int mark[1001],ans=n;
    memset(mark,0,sizeof(mark));
    b.push(n);
    mark[n]=1;
    while(!b.empty()){
        int u=b.front();
        b.pop();
        for(int i=0;i<a[u].size();i++){
            int v=a[u][i];
            if(!mark[v]){
                b.push(v);
                ans=max(ans,v);
                mark[v]=1;
            }
        }
    }
    return ans;
}
int main(){
    int n,m;
    cin>>n>>m;
    for(int i=0;i<m;i++){
        int u,v;
        cin>>u>>v;
        a[u].push_back(v);
    }
    for(int i=1;i<=n;i++){
        cout<<bfs(i)<<' ';
    }
    return 0;
}
